import ControlPointIcon from '@mui/icons-material/ControlPoint';
import DeleteOutlineRoundedIcon from '@mui/icons-material/DeleteOutlineRounded';
import RemoveCircleOutlineOutlinedIcon from '@mui/icons-material/RemoveCircleOutlineOutlined';
import { Box, CardMedia, Divider, IconButton, Typography, Stack } from "@mui/material";

const BasketItem = ({ addToOrder, deleteFromOrder, poster, removeFromOrder, id, name, price, quantity, color, size }) => {

    return (
        <Box sx={{ py: 2 }}>
            <Stack direction="row" spacing={2} alignItems="center">
                <Box sx={{ width: 80, height: 100, flexShrink: 0, borderRadius: '12px', overflow: 'hidden' }}>
                    <CardMedia
                        image={poster}
                        component="img"
                        alt={name}
                        sx={{ width: '100%', height: '100%', objectFit: 'cover' }}
                    />
                </Box>

                <Box sx={{ flexGrow: 1 }}>
                    <Typography 
                        variant="body2" 
                        component="a" 
                        href={'/' + id} 
                        sx={{ 
                            color: 'white', 
                            textDecoration: 'none', 
                            fontWeight: 700,
                            display: 'block',
                            mb: 0.5,
                            '&:hover': { color: 'primary.main' }
                        }}
                    >
                        {name.length > 40 ? name.slice(0, 40) + "..." : name}
                    </Typography>
                    
                    <Stack direction="row" spacing={2} alignItems="center">
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                            <Box sx={{ width: 14, height: 14, borderRadius: '50%', backgroundColor: color, border: '1px solid rgba(255,255,255,0.2)' }} />
                            <Typography variant="caption" sx={{ color: 'text.secondary', fontWeight: 600 }}>{size}</Typography>
                        </Box>
                        <Typography variant="body2" sx={{ fontWeight: 800, color: 'primary.main' }}>
                            {price} ₴
                        </Typography>
                    </Stack>
                </Box>

                <Stack alignItems="center" spacing={0.5}>
                    <IconButton 
                        size="small"
                        onClick={() => addToOrder({ poster, id, name, price, color, size })}
                        sx={{ color: 'text.secondary', '&:hover': { color: 'white' } }}
                    >
                        <ControlPointIcon fontSize="small" />
                    </IconButton>
                    
                    <Typography variant="body2" sx={{ fontWeight: 700 }}>
                        {quantity}
                    </Typography>

                    <IconButton 
                        size="small"
                        disabled={quantity <= 1}
                        onClick={() => deleteFromOrder({ poster, id, name, price, color, size })}
                        sx={{ color: 'text.secondary', '&:hover': { color: 'white' } }}
                    >
                        <RemoveCircleOutlineOutlinedIcon fontSize="small" />
                    </IconButton>
                </Stack>

                <IconButton
                    onClick={() => removeFromOrder(id, quantity, size, color)}
                    sx={{ color: 'rgba(255,255,255,0.3)', '&:hover': { color: 'error.main' } }}
                >
                    <DeleteOutlineRoundedIcon />
                </IconButton>
            </Stack>
            <Divider sx={{ mt: 2, opacity: 0.5 }} />
        </Box>
    );
};

export default BasketItem;
